SELECT cron.schedule('sync-indexes-oneshot-verify', '* * * * *', $$SELECT net.http_post(url := 'https://zcjptaolpumhtlwhlemq.supabase.co/functions/v1/sync-indexes', headers := jsonb_build_object('Content-Type','application/json','Authorization','Bearer ' || (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name = 'SYNC_SECRET' LIMIT 1)), body := '{}'::jsonb) AS request_id;$$);